/* wms-outbound-obPickingManager-sql-oracle.xml - selectTotPickingConfirmAbleQty - 총량피킹 상품코드/로케이션코드 별 피킹확정 처리 가능수량 조회 */
SELECT
	SUM(EXPCTQTY - PKFAILQTY) - SUM(CNFRMQTY) AS PKABLEQTY
FROM TWORK_INFO_PI_TOT_DT
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND PIHDKEY = #{pihdkey}
AND ICKEY = #{ickey}
AND LCKEY = #{lckey}
AND CELLKEY = #{cellkey}
AND PKWKSTATUSCD = '00'
GROUP BY CTKEY, OWKEY, PIHDKEY, ICKEY, LCKEY

