/* wms-outbound-obPickingManager-sql-oracle.xml - updateTotPickingConfirm - 총량피킹 확정 처리 */
UPDATE TWORK_INFO_PI_TOT_DT
SET CNFRMQTY = CNFRMQTY + #{cnfrmqty}
	,PKWKSTATUSCD = '10'
	,PKCNFRMDATE = #{sysdate}
	,PKCNFRMURKEY = #{surkey}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND PIHDKEY = #{pihdkey}
AND ICKEY = #{ickey}
AND LCKEY = #{lckey}
AND CELLKEY = #{cellkey}

	AND IVATKEY = #{ivatkey}

/* wms-outbound-obPickingManager-sql-oracle.xml - updateIntgPickingConfirm - 통합피킹 확정 처리 */
UPDATE TWORK_INFO_PI_INTG_DT
SET RSCNFRMQTY = RSCNFRMQTY + LEAST(COALESCE(RSEXPCTQTY, 0), COALESCE(#{cnfrmqty}, 0))
	,DASCNFRMQTY = DASCNFRMQTY + LEAST(DASEXPCTQTY, GREATEST(COALESCE(#{cnfrmqty} - RSEXPCTQTY, 0), 0))
	,PKWKSTATUSCD = '10'
	,PKCNFRMDATE = #{sysdate}
	,PKCNFRMURKEY = #{surkey}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND PIHDKEY = #{pihdkey}
AND ICKEY = #{ickey}
AND LCKEY = #{lckey}
AND CELLKEY = #{cellkey}

/* wms-outbound-obPickingManager-sql-oracle.xml - updateTotPickingConfirmQty - 총량피킹 확정수량 처리 */
