WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND PIHDKEY = #{pihdkey}
AND ICKEY = #{ickey}
AND LCKEY = #{lckey}
AND CELLKEY = #{cellkey}
AND IVATKEY = #{ivatkey}

