/* wms-outbound-obPickingManager-sql-oracle.xml - updateWaveHeaderWorkStatusCd - WA_HD의 작업상태 변경 */
UPDATE TWORK_INFO_WA_HD
SET WAWKSTATUSCD = #{wawkstatuscd}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND WAHDKEY = #{wahdkey}

/* wms-outbound-obPickingManager-sql-oracle.xml - updateOutboundDetailByPickingDetailConfirm - 출고상세 UPDATE(피킹수량/분류수량) BY PI_DT 확정 */
UPDATE TWORK_INFO_OB_DT
SET OBDTSTATUSCD = CASE WHEN PKISTQTY = (PKQTY + #{cnfrmqty}) THEN '30' /*30:피킹확정*/
						WHEN PKISTQTY > (PKQTY + #{cnfrmqty}) THEN '25' /*25:부분피킹*/
						ELSE OBDTSTATUSCD END
	,PKQTY = PKQTY + #{cnfrmqty}

		,CLASSIFSQTY = CLASSIFSQTY + #{cnfrmqty}

	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}
AND OBDTKEY = #{obdtkey}

