/* wms-outbound-obPickingManager-sql-oracle.xml - selectPickingTotalDetailForAllotment - 릴리즈오더 별 피킹확정수량 배정을 위한 총량피킹상세 조회 */
SELECT
	CTKEY
	,OWKEY
	,PIHDKEY
	,ICKEY
	,IVATKEY
	,LCKEY
	,CELLKEY
	,CNFRMQTY - DISPQTY AS REMAINQTY
FROM TWORK_INFO_PI_TOT_DT
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND PIHDKEY = #{pihdkey}
AND ICKEY = #{ickey}
AND IVATKEY = #{ivatkey}
AND LCKEY = #{lckey}
AND CELLKEY = #{cellkey}
AND PKWKSTATUSCD = '10'
AND CNFRMQTY - DISPQTY  >  0

