/* wms-outbound-obPickingManager-sql-oracle.xml - updatePickingDetailConfirmCancel - 피킹상세 확정취소 처리 */
UPDATE TWORK_INFO_PI_DT
SET CNFRMQTY = CNFRMQTY - #{cnfrmqty}
