/* wms-outbound-obPickingManager-sql-oracle.xml - updateTotPickingConfirmCancelAll - 총량피킹 확정 취소 처리(전체) */
UPDATE TWORK_INFO_PI_TOT_DT
SET CNFRMQTY = CNFRMQTY - #{cnfrmqty}
	,PKWKSTATUSCD = '00'
	,PKCNFRMDATE = NULL
	,PKCNFRMURKEY = NULL
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND PIHDKEY = #{pihdkey}
AND ICKEY = #{ickey}
AND LCKEY = #{lckey}
AND CELLKEY = #{cellkey}
AND IVATKEY = #{ivatkey}

/* wms-outbound-obPickingManager-sql-oracle.xml - updateOutboundDetailByPickingDetailConfirmCancel - 출고상세 UPDATE(피킹수량/분류수량) BY PI_DT 확정취소 */
UPDATE TWORK_INFO_OB_DT
SET OBDTSTATUSCD = CASE WHEN 0 = (PKQTY - #{cnfrmqty}) THEN '20' /*20:피킹지시*/
						ELSE (CASE WHEN PKISTQTY > (PKQTY - #{cnfrmqty})
									THEN '25'
									ELSE OBDTSTATUSCD END) END /*25:부분피킹*/
	,PKQTY = PKQTY - #{cnfrmqty}
	,CLASSIFSQTY = CLASSIFSQTY - #{cnfrmqty}
	,UPDATEDATE = #{sysdate}
	,UPDATEURKEY = #{surkey}
WHERE CTKEY = #{ctkey}
AND OWKEY = #{owkey}
AND OBHDKEY = #{obhdkey}
AND OBDTKEY = #{obdtkey}

		/* wms-outbound-obPickingManager-sql-oracle.xml - updateInventoryInvestigationTargetYn - 재고조사 대상여부 수정 */
		UPDATE TWORK_INFO_IVATXLC IVLC
		   SET IVLC.UPDATEDATE = #{sysdate}
			,  IVLC.UPDATEURKEY = #{surkey}
			,  IVLC.IVINVSTGTYN = 'Y'
		WHERE IVLC.CTKEY = #{ctkey}
		   AND IVLC.OWKEY = #{owkey}
		   AND IVLC.ICKEY = #{ickey}
		   AND EXISTS (
				SELECT 1
				FROM TWORK_MST_LC LC
					INNER JOIN TWORK_MST_ZN ZN
						ON LC.CTKEY = ZN.CTKEY
						AND LC.ZNKEY = ZN.ZNKEY
				WHERE LC.CTKEY = IVLC.CTKEY
				AND LC.LCKEY = IVLC.LCKEY
				AND ZN.ZNTYPECD = '10'
   		)

